import { ChangeDetectorRef, Component, OnDestroy, OnInit } from '@angular/core';
import { finalize, first } from 'rxjs/operators';

import { AccountService, AlertService } from '@app/_services';

@Component({
    templateUrl: 'list.component.html',
    standalone: false
})
export class ListComponent implements OnInit, OnDestroy {
    accounts: any[] = [];
    loading = false;

    private loadTimeoutId?: any;

    constructor(
        private accountService: AccountService,
        private alertService: AlertService,
        private cdr: ChangeDetectorRef
    ) {}

    ngOnInit() {
        this.loading = true;
        this.cdr.detectChanges();

        this.loadTimeoutId = setTimeout(() => {
            if (this.loading) {
                this.loading = false;
                this.accounts = [];
                this.alertService.error('Request timed out');
                this.cdr.detectChanges();
            }
        }, 10000);

        this.accountService.getAll()
            .pipe(
                first(),
                finalize(() => {
                    this.loading = false;
                    if (this.loadTimeoutId) {
                        clearTimeout(this.loadTimeoutId);
                        this.loadTimeoutId = undefined;
                    }
                    this.cdr.detectChanges();
                })
            )
            .subscribe({
                next: accounts => {
                    this.accounts = accounts;
                    this.cdr.detectChanges();
                },
                error: error => {
                    this.accounts = [];
                    this.alertService.error(error);
                    this.cdr.detectChanges();
                }
            });
    }

    ngOnDestroy() {
        if (this.loadTimeoutId) {
            clearTimeout(this.loadTimeoutId);
            this.loadTimeoutId = undefined;
        }
    }

    deleteAccount(id: string) {
        const account = this.accounts.find(x => x.id === id);
        if (!account) return;

        account.isDeleting = true;
        this.cdr.detectChanges();

        this.accountService.delete(id)
            .pipe(first())
            .subscribe({
                next: () => {
                    this.accounts = this.accounts.filter(x => x.id !== id);
                    this.cdr.detectChanges();
                }
            });
    }
}
<div class="page-header d-flex justify-content-between align-items-center">
    <div>
        <h2 class="page-title">User Accounts</h2>
        <p class="page-subtitle">All registered system user accounts</p>
    </div>
    <a routerLink="add" class="btn btn-success"><i class="bi bi-person-plus-fill me-1"></i> Create Account</a>
</div>

<div class="card">
    <div class="table-responsive">
        <table class="table table-hover table-striped">
            <thead>
                <tr>
                    <th style="width: 30%">Name</th>
                    <th style="width: 35%">Email</th>
                    <th style="width: 20%">Role</th>
                    <th style="width: 15%"></th>
                </tr>
            </thead>
            <tbody>
                <tr *ngFor="let account of accounts">
                    <td class="fw-semibold align-middle">{{account.title}} {{account.firstName}} {{account.lastName}}</td>
                    <td class="align-middle">{{account.email}}</td>
                    <td class="align-middle"><span class="badge bg-secondary font-monospace">{{account.role}}</span></td>
                    <td class="text-end align-middle" style="white-space: nowrap">
                        <a routerLink="edit/{{account.id}}" class="btn btn-sm btn-primary me-2"><i class="bi bi-pencil-square"></i> Edit</a>
                        <button (click)="deleteAccount(account.id)" class="btn btn-sm btn-danger" [disabled]="account.isDeleting">
                            <span *ngIf="account.isDeleting" class="spinner-border spinner-border-sm"></span>
                            <span *ngIf="!account.isDeleting"><i class="bi bi-trash"></i></span>
                        </button>
                    </td>
                </tr>
                <tr *ngIf="loading">
                    <td colspan="4" class="text-center p-4">
                        <span class="spinner-border spinner-border-lg text-primary"></span>
                    </td>
                </tr>
                <tr *ngIf="!loading && accounts.length === 0">
                    <td colspan="4" class="text-center text-muted p-4">
                        No accounts found.
                    </td>
                </tr>
            </tbody>
        </table>
    </div>
</div>
